const items = $input.all();
const results = [];

for (const item of items) {
  const text = item.json.body?.text || "";

  // Buscar monto: Ej "Bs. 500,00" o "500.50"
  let monto = "0.00";
  const montoMatch = text.match(/(?:Bs\.?\s*|monto\s*|Bs\.\s*)?(\d{1,3}(?:[.,]\d{3})*(?:[.,]\d{1,2})?)/i);
  if (montoMatch) {
    monto = montoMatch[1].replace(',', '.'); // Normalizar decimales a punto
  }

  // Buscar Referencia: Busca explícitamente "Ref:", "Referencia:" etc.
  let referencia = "Desconocida";
  const refMatch = text.match(/(?:Ref(?:erencia)?[:\s]*)(\d{6,12})/i);
  if (refMatch) {
    referencia = refMatch[1];
  } else {
    // Intentar buscar un conjunto de dígitos largos como respaldo al final o en algún lugar
    const fallbackRef = text.match(/\b\d{6,12}\b/g);
    if(fallbackRef) {
       // Buscar el primer número largo que no empiece con 04 (teléfono)
       const nonPhone = fallbackRef.find(r => !r.startsWith('04'));
       if(nonPhone) referencia = nonPhone;
       else if(fallbackRef.length > 0) referencia = fallbackRef[fallbackRef.length - 1]; // ultimo numero largo
    }
  }

  // Identificar Banco
  let banco = "Desconocido";
  const textLower = text.toLowerCase();
  if (textLower.includes("bdv") || textLower.includes("venezuela") || textLower.includes("pagomovilbdv")) banco = "BDV";
  else if (textLower.includes("banesco")) banco = "Banesco";
  else if (textLower.includes("mercantil")) banco = "Mercantil";
  else if (textLower.includes("provincial") || textLower.includes("bbva")) banco = "Provincial";
  else if (textLower.includes("bnc")) banco = "BNC";
  else if (textLower.includes("bancamiga")) banco = "Bancamiga";

  // Retornar la estructura deseada
  results.push({
    json: {
      banco: banco,
      monto: parseFloat(monto) || 0,
      referencia: referencia,
      texto_original: text
    }
  });
}
return results;
